sealed class ProllyBindingException: kotlin.Exception() {

    class InvalidArgument(
        override val `message`: kotlin.String
        ) : ProllyBindingException()

    class InvalidCid(
        override val `message`: kotlin.String
        ) : ProllyBindingException()

    class InvalidNode(
        override val `message`: kotlin.String
        ) : ProllyBindingException()

    class NotFound(
        override val `message`: kotlin.String
        ) : ProllyBindingException()

    class Conflict(
        override val `message`: kotlin.String
        ) : ProllyBindingException()

    class Store(
        override val `message`: kotlin.String
        ) : ProllyBindingException()

    class Serialization(
        override val `message`: kotlin.String
        ) : ProllyBindingException()

    class Internal(
        override val `message`: kotlin.String
        ) : ProllyBindingException()





    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<ProllyBindingException> {
        override fun lift(error_buf: RustBuffer.ByValue): ProllyBindingException = FfiConverterTypeProllyBindingError.lift(error_buf)
    }


}

/**
 * @suppress
 */
public object FfiConverterTypeProllyBindingError : FfiConverterRustBuffer<ProllyBindingException> {
    override fun read(buf: ByteBuffer): ProllyBindingException {


        return when(buf.getInt()) {
            1 -> ProllyBindingException.InvalidArgument(
                FfiConverterString.read(buf),
                )
            2 -> ProllyBindingException.InvalidCid(
                FfiConverterString.read(buf),
                )
            3 -> ProllyBindingException.InvalidNode(
                FfiConverterString.read(buf),
                )
            4 -> ProllyBindingException.NotFound(
                FfiConverterString.read(buf),
                )
            5 -> ProllyBindingException.Conflict(
                FfiConverterString.read(buf),
                )
            6 -> ProllyBindingException.Store(
                FfiConverterString.read(buf),
                )
            7 -> ProllyBindingException.Serialization(
                FfiConverterString.read(buf),
                )
            8 -> ProllyBindingException.Internal(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ProllyBindingException): ULong {
        return when(value) {
            is ProllyBindingException.InvalidArgument -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is ProllyBindingException.InvalidCid -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is ProllyBindingException.InvalidNode -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is ProllyBindingException.NotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is ProllyBindingException.Conflict -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is ProllyBindingException.Store -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is ProllyBindingException.Serialization -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is ProllyBindingException.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
        }
    }

    override fun write(value: ProllyBindingException, buf: ByteBuffer) {
        when(value) {
            is ProllyBindingException.InvalidArgument -> {
                buf.putInt(1)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is ProllyBindingException.InvalidCid -> {
                buf.putInt(2)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is ProllyBindingException.InvalidNode -> {
                buf.putInt(3)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is ProllyBindingException.NotFound -> {
                buf.putInt(4)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is ProllyBindingException.Conflict -> {
                buf.putInt(5)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is ProllyBindingException.Store -> {
                buf.putInt(6)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is ProllyBindingException.Serialization -> {
                buf.putInt(7)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is ProllyBindingException.Internal -> {
                buf.putInt(8)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




